// Combine all three review results
const content = $('Prepare for Review').first().json;
const voiceRaw = $('Claude: Brand Voice Check').first().json;
const sanskritRaw = $('Claude: Sanskrit Accuracy').first().json;
const qualityRaw = $('Claude: Quality Score').first().json;

function parseClaudeJSON(raw) {
  const text = raw.text || raw.message?.content?.[0]?.text || JSON.stringify(raw);
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  return JSON.parse(cleaned);
}

const voice = parseClaudeJSON(voiceRaw);
const sanskrit = parseClaudeJSON(sanskritRaw);
const quality = parseClaudeJSON(qualityRaw);

const totalScore = quality.total_score;
const passesAllChecks = voice.voice_pass && sanskrit.accuracy_pass && totalScore >= 7;

return [{
  json: {
    content_piece_id: content.id,
    content_type: content.content_type,
    verse_id: content.verse_id,
    brand_voice: voice,
    sanskrit_accuracy: sanskrit,
    quality: quality,
    total_score: totalScore,
    decision: passesAllChecks ? 'approved' : 'in_review',
    reviewed_at: new Date().toISOString()
  }
}];

